```rust
struct FenwickTree {
    size: usize,
    tree: Vec<i64>,
}

impl FenwickTree {
    fn new(size: usize) -> Self {
        let mut tree = vec![0; size + 1];
        Self { size, tree }
    }

    fn update(&mut self, idx: usize, delta: i64) {
        let i = idx + 1;
        while i <= self.size {
            self.tree[i] += delta;
            i += i & -i;
        }
    }

    fn query(&self, idx: usize) -> i64 {
        let i = idx + 1;
        let mut res = 0;
        while i > 0 {
            res += self.tree[i];
            i -= i & -i;
        }
        res
    }

    fn range_query(&self, l: usize, r: usize) -> i64 {
        let sum_r = self.query(r);
        let sum_l_1 = if l == 0 { 0 } else { self.query(l - 1) };
        sum_r - sum_l_1
    }
}

fn get_depth(x: i64) -> i32 {
    let mut current = x;
    let mut depth = 0;
    while current != 1 {
        current = current.bit_count() as i64;
        depth += 1;
    }
    depth
}

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let n = nums.len();
    let mut ft = vec![FenwickTree::new(n); 6];
    for i in 0..n {
        let x = nums[i];
        let d = get_depth(x);
        if d <= 5 {
            ft[d as usize].update(i, 1);
        }
    }
    let mut answer = Vec::new();
    for q in queries {
        if q[0] == 1 {
            let l = q[1] as usize;
            let r = q[2] as usize;
            let k = q[3] as usize;
            if k < 6 {
                let res = ft[k].range_query(l, r);
                answer.push(res);
            } else {
                answer.push(0);
            }
        } else {
            let idx = q[1] as usize;
            let val = q[2];
            let old_val = nums[idx];
            let old_d = get_depth(old_val);
            if old_d <= 5 {
                ft[old_d as usize].update(idx, -1);
            }
            let new_d = get_depth(val);
            if new_d <= 5 {
                ft[new_d as usize].update(idx, 1);
            }
            nums[idx] = val;
        }
    }
    answer
}
