    fn update(&mut self, idx: usize, delta: i64) {
        let i = idx + 1; // 1-based index
        let mut x = i;
        while x <= self.size {
            self.tree[x] += delta;
            x += x & -x;
        }
    }

    fn query(&self, idx: usize) -> i64 {
        let i = idx + 1;
        let mut res = 0;
        while i > 0 {
            res += self.tree[i];
            i -= i & -i;
        }
        res
    }

    fn range_query(&self, l: usize, r: usize) -> i64 {
        if l > r {
            return 0;
        }
        self.query(r) - self.query(l - 1)
    }
}

fn compute_depth(x: i64) -> i64 {
    let mut current = x;
    let mut depth = 0;
    while current != 1 {
        current = current.bit_count();
        depth += 1;
    }
    depth
}

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let n = nums.len();
    let mut bit_trees: Vec<FenwickTree> = vec![FenwickTree::new(n); 6];

    for i in 0..n {
        let val = nums[i];
        let depth = compute_depth(val);
        if depth >= 0 && depth <= 5 {
            bit_trees[depth as usize].update(i, 1);
        }
    }

    let mut answer = Vec::new();

    for query in queries {
        if query[0] == 1 {
            let l = query[1] as usize;
            let r = query[2] as usize;
            let k = query[3] as usize;
            let res = bit_trees[k].range_query(l, r);
            answer.push(res);
        } else {
            let idx = query[1] as usize;
            let val = query[2];
            // Update the value at idx
            let old_val = nums[idx];
            let old_depth = compute_depth(old_val);
            if old_depth >= 0 && old_depth <= 5 {
                bit_trees[old_depth as usize].update(idx, -1);
            }
            nums[idx] = val;
            let new_depth = compute_depth(val);
            if new_depth >= 0 && new_depth <= 5 {
                bit_trees[new_depth as usize].update(idx, 1);
            }
        }
    }

    answer
}
